function solve(n: number, edges: number[][], k: number): number {
    edges.sort((a, b) => a[2] - b[2]);
    if (edges.length === 0) {
        return 0;
    }
    let low = 0, high = edges[edges.length - 1][2];
    let answer = high;

    function countComponents(t: number): number {
        const parent = Array(n).fill(0).map((_, i) => i);
        const rank = Array(n).fill(1);

        function find(u: number): number {
            while (parent[u] !== u) {
                parent[u] = parent[parent[u]];
                u = parent[u];
            }
            return u;
        }

        function union(u: number, v: number): void {
            const uRoot = find(u);
            const vRoot = find(v);
            if (uRoot === vRoot) return;
            if (rank[uRoot] < rank[vRoot]) {
                parent[uRoot] = vRoot;
            } else {
                parent[vRoot] = uRoot;
                if (rank[uRoot] === rank[vRoot]) {
                    rank[uRoot]++;
                }
            }
        }

        for (const [u, v, time] of edges) {
            if (time > t) {
                union(u, v);
            }
        }

        const roots = new Set<number>();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const comp = countComponents(mid);
        if (comp >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
